for article in articles:
    text = (article['title'] + " " + article['description']).lower()
    scores = {cat: 0 for cat in keywords}
    
    for cat, words in keywords.items():
        for word in words:
            # Simple substring match might be too aggressive (e.g. "us" in "virus")
            # Use word boundary
            if re.search(r'\b' + re.escape(word) + r'\b', text):
                scores[cat] += 1
    
    # Heuristics
    if "gameboy" in text or "video game" in text or "nintendo" in text or "xbox" in text or "playstation" in text:
        scores["Sci/Tech"] += 5
    if "science" in text:
        scores["Sci/Tech"] += 5
    if "nasa" in text or "space" in text:
        scores["Sci/Tech"] += 5
    if "software" in text or "internet" in text or "computer" in text:
        scores["Sci/Tech"] += 3
    if "profit" in text or "revenue" in text or "quarter" in text or "earnings" in text:
        scores["Business"] += 5
    if "stock" in text or "market" in text or "price" in text:
        scores["Business"] += 3
    if "iraq" in text or "war" in text or "president" in text or "minister" in text:
        scores["World"] += 5
    if "olympic" in text or "cup" in text or "game" in text and "video" not in text:
        scores["Sports"] += 3
    if "team" in text and "science" not in text:
        scores["Sports"] += 3
        
    # Tie breaking
    # "Intel" -> Tech company. If revenue -> Business.
    # "Microsoft" -> Tech company. If lawsuit -> World/Business? Or Sci/Tech?
    # AG News classifies "Microsoft settles with UK phone maker" as Sci/Tech usually.
    # Let's favor Sci/Tech for Tech companies unless clearly financial report.
    
    best_cat = max(scores, key=scores.get)
    if scores[best_cat] == 0:
        best_cat = "Unknown"
        
    if best_cat == "Sci/Tech":
        sci_tech_titles.append(article['title'])
    elif best_cat == "Business":
        business_titles.append(article['title'])
    elif best_cat == "Sports":
        sports_titles.append(article['title'])
    elif best_cat == "World":
        world_titles.append(article['title'])
        
    total += 1

print("__RESULT__:")
